/// <summary>
/// Sales agreement import
/// </summary>
public class ETG_Acu_SalesAgreementHeaderImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_SalesAgreementHeaderImport  salesAgreementHeaderimport;

    salesAgreementHeaderimport = ETG_Acu_SalesAgreementHeaderImport::construct();

    if (salesAgreementHeaderimport.prompt())
    {
        salesAgreementHeaderimport.runOperation();
    }
}

public static ETG_Acu_SalesAgreementHeaderImport construct()
{
    return new ETG_Acu_SalesAgreementHeaderImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    SalesAgreementHeaderEntity    salesAgreementHeader;

    CustTable                   custTable;
    DirPartyBaseEntity          custTableDirParty;

    select firstonly custTable
        exists join custTableDirParty
        where custTableDirParty.PartyRecordId  == custTable.Party
            && custTableDirParty.OrganizationNumber == conpeek(_con, 2);

    salesAgreementHeader.SalesAgreementId                       = conpeek(_con, 1);
    salesAgreementHeader.AgreementCustomerAccountNumber         = custTable.AccountNum;
    salesAgreementHeader.AGREEMENTSTATUS                        = AgreementState::Effective;
    salesAgreementHeader.AgreementType                          = conpeek(_con, 4);

    if (conpeek(_con, 5))
    {
        select firstonly custTable
            exists join custTableDirParty
            where custTableDirParty.PartyRecordId  == custTable.Party
                && custTableDirParty.OrganizationNumber == conpeek(_con, 5);

        salesAgreementHeader.BuyerAccountNum                        = custTable.AccountNum;
    }
    salesAgreementHeader.BuyerBank                              = conpeek(_con, 6);
    salesAgreementHeader.Consignee                              = conpeek(_con, 7);
    salesAgreementHeader.CurrencyCode                           = conpeek(_con, 8);
    salesAgreementHeader.DefaultCommitmentType                  = CommitmentType::ProductQuantity;
    salesAgreementHeader.DefaultEffectiveDate                   = str2Date(conpeek(_con, 10), 123);
    salesAgreementHeader.DefaultExpirationDate                  = str2Date(conpeek(_con, 11), 123);
    salesAgreementHeader.DeliveryModeCode                       = conpeek(_con, 12);
    salesAgreementHeader.DeliveryTermsCode                      = conpeek(_con, 13);
    salesAgreementHeader.ExternalDocumentReference              = conpeek(_con, 14);
    salesAgreementHeader.Notifytodifferentparty                 = conpeek(_con, 15);
    salesAgreementHeader.PaymentTermsName                       = conpeek(_con, 16);
    salesAgreementHeader.PortOfDischarge                        = conpeek(_con, 17);
    salesAgreementHeader.PortOfDischargeDesc                    = conpeek(_con, 18);
    salesAgreementHeader.PortOfLoading                          = conpeek(_con, 19);
    salesAgreementHeader.PortOfLoadingDesc                      = conpeek(_con, 20);
    salesAgreementHeader.salesAgreementClassificationName       = conpeek(_con, 21);
    salesAgreementHeader.salesOrderPoolId                       = conpeek(_con, 22);
    salesAgreementHeader.SellerAccountNum                       = conpeek(_con, 23);
    salesAgreementHeader.SellerBank                             = conpeek(_con, 24);
    salesAgreementHeader.SellingLegalEntityId                   = curExt();
    salesAgreementHeader.Through                                = conpeek(_con, 26);

    salesAgreementHeader.InvoiceCustomerAccountNumber           = salesAgreementHeader.AgreementCustomerAccountNumber;

    // BusinessUnit (27)	Contract (28)	Department (29)	Intercompany (30)	Plant_Warehouse_Office (31)	Product_Service (32)	Trader_Employee (33)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    salesAgreementHeader.DefaultLedgerDimensionDisplayValue     = conPeek(_con, 31) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 29) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 33) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 32) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 27) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 30) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 28);
    salesAgreementHeader.insert();
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpSalesAgreementHeader";

    return ret;
}
